#!/usr/bin/env node
// ============================================================================
// CI Coverage Gate — Hard-fail if coverage drops below thresholds.
//
// Reads coverage/coverage-summary.json (generated by vitest --coverage).
// Exits with code 1 if any threshold is breached.
//
// Run after: vitest run --coverage
// ============================================================================

import { readFileSync, existsSync } from "node:fs";
import { join } from "node:path";

const ROOT = new URL("../../../..", import.meta.url).pathname.replace(/^\/([A-Z]:)/, "$1");
const SUMMARY_PATH = join(ROOT, "coverage", "coverage-summary.json");

const THRESHOLDS = {
  // Global thresholds
  global: { statements: 60, branches: 50, functions: 85, lines: 60 },
  // CLI-specific thresholds (lower since CLI has terminal I/O hard to unit test)
  cli: { statements: 40, branches: 35, functions: 60, lines: 40 },
};

if (!existsSync(SUMMARY_PATH)) {
  console.error(
    `Coverage summary not found at ${SUMMARY_PATH}.\n` +
    `Run 'npm test -- --coverage' first.`,
  );
  process.exit(1);
}

let summary;
try {
  summary = JSON.parse(readFileSync(SUMMARY_PATH, "utf-8"));
} catch (e) {
  console.error(`Failed to parse coverage summary: ${e.message}`);
  process.exit(1);
}

const total = summary.total;
if (!total) {
  console.error("coverage-summary.json has no 'total' key — unexpected format");
  process.exit(1);
}

let failed = false;

function check(label, actual, required) {
  if (actual < required) {
    console.error(
      `  FAIL  ${label}: ${actual.toFixed(1)}% < ${required}% required`,
    );
    return false;
  }
  console.log(`  PASS  ${label}: ${actual.toFixed(1)}% (threshold: ${required}%)`);
  return true;
}

console.log("\nCoverage Gate Check\n" + "─".repeat(60));

// Check global thresholds
const pct = (metric) => (total[metric]?.pct ?? 0);
if (!check("statements (global)", pct("statements"), THRESHOLDS.global.statements)) failed = true;
if (!check("branches   (global)", pct("branches"),   THRESHOLDS.global.branches))   failed = true;
if (!check("functions  (global)", pct("functions"),  THRESHOLDS.global.functions))  failed = true;
if (!check("lines      (global)", pct("lines"),      THRESHOLDS.global.lines))      failed = true;

console.log("");

// Check per-file stats for CLI package
let cliStmtTotal = 0, cliStmtCovered = 0;
let cliBranchTotal = 0, cliBranchCovered = 0;
let cliFuncTotal = 0, cliFuncCovered = 0;
let cliLineTotal = 0, cliLineCovered = 0;
let cliFileCount = 0;

for (const [filePath, stats] of Object.entries(summary)) {
  if (filePath === "total") continue;
  if (!filePath.includes("packages/cli/src") && !filePath.includes("packages\\cli\\src")) continue;
  cliFileCount++;
  cliStmtTotal    += stats.statements?.total  ?? 0;
  cliStmtCovered  += stats.statements?.covered ?? 0;
  cliBranchTotal  += stats.branches?.total    ?? 0;
  cliBranchCovered += stats.branches?.covered ?? 0;
  cliFuncTotal    += stats.functions?.total   ?? 0;
  cliFuncCovered  += stats.functions?.covered ?? 0;
  cliLineTotal    += stats.lines?.total       ?? 0;
  cliLineCovered  += stats.lines?.covered     ?? 0;
}

if (cliFileCount > 0) {
  const cliStmtPct  = cliStmtTotal  > 0 ? (cliStmtCovered  / cliStmtTotal)  * 100 : 0;
  const cliBranchPct= cliBranchTotal > 0 ? (cliBranchCovered / cliBranchTotal) * 100 : 0;
  const cliFuncPct  = cliFuncTotal  > 0 ? (cliFuncCovered  / cliFuncTotal)  * 100 : 0;
  const cliLinePct  = cliLineTotal  > 0 ? (cliLineCovered  / cliLineTotal)  * 100 : 0;

  if (!check("statements (cli)", cliStmtPct,  THRESHOLDS.cli.statements)) failed = true;
  if (!check("branches   (cli)", cliBranchPct, THRESHOLDS.cli.branches))  failed = true;
  if (!check("functions  (cli)", cliFuncPct,  THRESHOLDS.cli.functions))  failed = true;
  if (!check("lines      (cli)", cliLinePct,  THRESHOLDS.cli.lines))      failed = true;
  console.log(`\n  CLI files checked: ${cliFileCount}`);
}

console.log("─".repeat(60));

if (failed) {
  console.error("\nCoverage gate FAILED — see errors above\n");
  process.exit(1);
} else {
  console.log("\nCoverage gate PASSED\n");
  process.exit(0);
}
